import json
import time
import hashlib
import secrets
from datetime import datetime, timedelta
from typing import Optional, Dict

from flask import Flask, request, jsonify
from flask_cors import CORS
from web3 import Web3
from eth_account.messages import encode_defunct
import jwt

app = Flask(__name__)
CORS(app)

# Configuration
app.config['SECRET_KEY'] = secrets.token_hex(32)
app.config['JWT_EXPIRATION_HOURS'] = 24
app.config['NONCE_EXPIRATION_MINUTES'] = 5

# In-memory stores (use Redis/DB in production)
nonce_store: Dict[str, dict] = {}
session_store: Dict[str, dict] = {}
user_store: Dict[str, dict] = {}

# Initialize Web3
w3 = Web3()


def generate_nonce() -> str:
    """Generate a cryptographically secure random nonce."""
    return secrets.token_hex(16)


def create_sign_message(address: str, nonce: str, timestamp: int) -> str:
    """Create a standardized message for signing."""
    return (
        f"Welcome to Web3 Auth!\n\n"
        f"Please sign this message to authenticate.\n\n"
        f"Wallet: {address}\n"
        f"Nonce: {nonce}\n"
        f"Timestamp: {timestamp}\n\n"
        f"This request will expire in {app.config['NONCE_EXPIRATION_MINUTES']} minutes."
    )


def generate_jwt_token(address: str) -> str:
    """Generate a JWT token for authenticated user."""
    payload = {
        'sub': address.lower(),
        'iat': datetime.utcnow(),
        'exp': datetime.utcnow() + timedelta(hours=app.config['JWT_EXPIRATION_HOURS']),
        'jti': secrets.token_hex(16),
    }
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')


def verify_jwt_token(token: str) -> Optional[dict]:
    """Verify and decode a JWT token."""
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def recover_address_from_signature(message: str, signature: str) -> Optional[str]:
    """Recover Ethereum address from a signed message."""
    try:
        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(
            encoded_message, signature=signature
        )
        return recovered_address
    except Exception as e:
        print(f"Error recovering address: {e}")
        return None


def cleanup_expired_nonces():
    """Remove expired nonces from the store."""
    current_time = time.time()
    expired = [
        addr for addr, data in nonce_store.items()
        if current_time - data['timestamp'] > app.config['NONCE_EXPIRATION_MINUTES'] * 60
    ]
    for addr in expired:
        del nonce_store[addr]


def require_auth(f):
    """Decorator to require JWT authentication."""
    from functools import wraps

    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid authorization header'}), 401

        token = auth_header.split(' ')[1]
        payload = verify_jwt_token(token)

        if not payload:
            return jsonify({'error': 'Invalid or expired token'}), 401

        request.user_address = payload['sub']
        return f(*args, **kwargs)

    return decorated


@app.route('/api/auth/nonce', methods=['POST'])
def request_nonce():
    """
    Step 1: Client requests a nonce for their wallet address.
    The nonce is used to create a unique message for signing.
    """
    data = request.get_json()

    if not data or 'address' not in data:
        return jsonify({'error': 'Wallet address is required'}), 400

    address = data['address']

    # Validate Ethereum address
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    # Normalize address to checksum format
    address = w3.to_checksum_address(address)

    # Cleanup expired nonces
    cleanup_expired_nonces()

    # Generate nonce and timestamp
    nonce = generate_nonce()
    timestamp = int(time.time())

    # Create the message to be signed
    message = create_sign_message(address, nonce, timestamp)

    # Store nonce with metadata
    nonce_store[address.lower()] = {
        'nonce': nonce,
        'timestamp': timestamp,
        'message': message,
    }

    return jsonify({
        'message': message,
        'nonce': nonce,
        'timestamp': timestamp,
        'expires_in': app.config['NONCE_EXPIRATION_MINUTES'] * 60,
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
def verify_signature():
    """
    Step 2: Client submits the signed message.
    Server recovers the address and verifies it matches.
    """
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    required_fields = ['address', 'signature']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': f'{field} is required'}), 400

    address = data['address']
    signature = data['signature']

    # Validate Ethereum address
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    address = w3.to_checksum_address(address)
    address_lower = address.lower()

    # Check if nonce exists for this address
    if address_lower not in nonce_store:
        return jsonify({'error': 'No authentication request found. Please request a nonce first.'}), 400

    nonce_data = nonce_store[address_lower]

    # Check if nonce has expired
    current_time = time.time()
    if current_time - nonce_data['timestamp'] > app.config['NONCE_EXPIRATION_MINUTES'] * 60:
        del nonce_store[address_lower]
        return jsonify({'error': 'Nonce has expired. Please request a new one.'}), 400

    # Recover address from signature
    message = nonce_data['message']
    recovered_address = recover_address_from_signature(message, signature)

    if not recovered_address:
        return jsonify({'error': 'Failed to recover address from signature'}), 400

    # Verify the recovered address matches the claimed address
    if recovered_address.lower() != address_lower:
        return jsonify({
            'error': 'Signature verification failed. Recovered address does not match.',
            'expected': address,
            'recovered': recovered_address,
        }), 401

    # Authentication successful - remove used nonce (prevent replay attacks)
    del nonce_store[address_lower]

    # Create or update user record
    if address_lower not in user_store:
        user_store[address_lower] = {
            'address': address,
            'created_at': datetime.utcnow().isoformat(),
            'last_login': datetime.utcnow().isoformat(),
            'login_count': 1,
        }
    else:
        user_store[address_lower]['last_login'] = datetime.utcnow().isoformat()
        user_store[address_lower]['login_count'] += 1

    # Generate JWT token
    token = generate_jwt_token(address)

    # Store session
    session_id = secrets.token_hex(16)
    session_store[session_id] = {
        'address': address_lower,
        'created_at': datetime.utcnow().isoformat(),
        'token': token,
    }

    return jsonify({
        'authenticated': True,
        'address': address,
        'token': token,
        'session_id': session_id,
        'expires_in': app.config['JWT_EXPIRATION_HOURS'] * 3600,
        'user': user_store[address_lower],
    }), 200


@app.route('/api/auth/refresh', methods=['POST'])
@require_auth
def refresh_token():
    """Refresh an existing JWT token."""
    new_token = generate_jwt_token(request.user_address)

    return jsonify({
        'token': new_token,
        'address': request.user_address,
        'expires_in': app.config['JWT_EXPIRATION_HOURS'] * 3600,
    }), 200


@app.route('/api/auth/logout', methods=['POST'])
@require_auth
def logout():
    """Invalidate the current session."""
    data = request.get_json() or {}
    session_id = data.get('session_id')

    if session_id and session_id in session_store:
        del session_store[session_id]

    return jsonify({'message': 'Successfully logged out'}), 200


@app.route('/api/auth/me', methods=['GET'])
@require_auth
def get_current_user():
    """Get the currently authenticated user's profile."""
    address = request.user_address

    if address not in user_store:
        return jsonify({'error': 'User not found'}), 404

    return jsonify({
        'authenticated': True,
        'user': user_store[address],
    }), 200


